import{_ as o,o as t,c as r,a0 as a}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"API Reference","description":"Complete parameters reference guide for plot_map_r function in geoplot-themes.","frontmatter":{"title":"API Reference","description":"Complete parameters reference guide for plot_map_r function in geoplot-themes."},"headers":[],"relativePath":"api/reference.md","filePath":"api/reference.md"}'),l={name:"api/reference.md"};function c(i,e,s,n,d,u){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="comprehensive-api-reference" tabindex="-1">Comprehensive API Reference <a class="header-anchor" href="#comprehensive-api-reference" aria-label="Permalink to &quot;Comprehensive API Reference&quot;">​</a></h1><p>This is the complete list of every single parameter accepted by <code>plot_map_r()</code>.</p><h2 id="plot-map-r" tabindex="-1"><code>plot_map_r(...)</code> <a class="header-anchor" href="#plot-map-r" aria-label="Permalink to &quot;`plot_map_r(...)`&quot;">​</a></h2><h3 id="data-layers" tabindex="-1">Data Layers <a class="header-anchor" href="#data-layers" aria-label="Permalink to &quot;Data Layers&quot;">​</a></h3><ul><li><strong><code>raster_data</code></strong> <em>(str, optional)</em>: Path to <code>.tif</code> raster file.</li><li><strong><code>vector_data</code></strong> <em>(str, optional)</em>: Path to the primary <code>.shp</code> vector file.</li><li><strong><code>vector_column</code></strong> <em>(str, optional)</em>: If provided, colors the primary vector by this column.</li><li><strong><code>vector_discrete</code></strong> <em>(bool)</em>: Set <code>True</code> if <code>vector_column</code> is categorical. Default <code>False</code>.</li><li><strong><code>extra_vectors</code></strong> <em>(list of dict, optional)</em>: Infinite layers. Example: <code>[{&quot;data&quot;: &quot;swamp.shp&quot;, &quot;name&quot;: &quot;Swamp&quot;, &quot;fill&quot;: &quot;#2d5a27&quot;}]</code>.</li></ul><h3 id="point-layers" tabindex="-1">Point Layers <a class="header-anchor" href="#point-layers" aria-label="Permalink to &quot;Point Layers&quot;">​</a></h3><ul><li><strong><code>points_data</code></strong> <em>(str, optional)</em>: Path to point <code>.shp</code> or <code>.csv</code>.</li><li><strong><code>points_color_column</code></strong> <em>(str, optional)</em>: Column to color points.</li><li><strong><code>points_label_column</code></strong> <em>(str, optional)</em>: Column to draw repelled text labels.</li><li><strong><code>points_discrete</code></strong> <em>(bool)</em>: Set <code>True</code> if color column is categorical. Default <code>True</code>.</li></ul><h3 id="styling" tabindex="-1">Styling <a class="header-anchor" href="#styling" aria-label="Permalink to &quot;Styling&quot;">​</a></h3><ul><li><strong><code>theme</code></strong> <em>(str)</em>: <code>&quot;natgeo_minimalist&quot;</code>, <code>&quot;dark_matter&quot;</code>, or <code>&quot;retro_blueprint&quot;</code>. Default <code>&quot;natgeo_minimalist&quot;</code>.</li><li><strong><code>colormap</code></strong> <em>(str)</em>: <code>&quot;elevation&quot;</code>, <code>&quot;neon&quot;</code>, <code>&quot;blueprint&quot;</code>, etc. Default <code>&quot;elevation&quot;</code>.</li><li><strong><code>orientation</code></strong> <em>(str)</em>: <code>&quot;auto&quot;</code>, <code>&quot;portrait&quot;</code>, or <code>&quot;landscape&quot;</code>. Default <code>&quot;auto&quot;</code>.</li></ul><h3 id="map-elements" tabindex="-1">Map Elements <a class="header-anchor" href="#map-elements" aria-label="Permalink to &quot;Map Elements&quot;">​</a></h3><ul><li><strong><code>title</code></strong> <em>(str)</em>: Main header.</li><li><strong><code>subtitle</code></strong> <em>(str)</em>: Sub header.</li><li><strong><code>author</code></strong> <em>(str)</em>: Footer row 1.</li><li><strong><code>date_str</code></strong> <em>(str)</em>: Footer row 2.</li><li><strong><code>data_source</code></strong> <em>(str)</em>: Footer row 3.</li><li><strong><code>crs_text</code></strong> <em>(str)</em>: Footer row 4.</li></ul><h3 id="toggles" tabindex="-1">Toggles <a class="header-anchor" href="#toggles" aria-label="Permalink to &quot;Toggles&quot;">​</a></h3><ul><li><strong><code>show_coords</code></strong> <em>(bool)</em>: Show lat/long grid. Default <code>True</code>.</li><li><strong><code>scale_bar</code></strong> <em>(bool)</em>: Show distance scale. Default <code>True</code>.</li><li><strong><code>north_arrow</code></strong> <em>(bool)</em>: Show compass arrow. Default <code>True</code>.</li></ul><h3 id="insets" tabindex="-1">Insets <a class="header-anchor" href="#insets" aria-label="Permalink to &quot;Insets&quot;">​</a></h3><ul><li><strong><code>inset_map</code></strong> <em>(str, optional)</em>: Path to vector file for the floating inset map.</li><li><strong><code>inset_position</code></strong> <em>(list of float)</em>: <code>[x, y]</code> coordinates from <code>0</code> to <code>1</code>. Default <code>[0.7, 0.7]</code>.</li><li><strong><code>inset_scale</code></strong> <em>(float)</em>: Size of inset relative to canvas. Default <code>0.25</code>.</li></ul><h3 id="output" tabindex="-1">Output <a class="header-anchor" href="#output" aria-label="Permalink to &quot;Output&quot;">​</a></h3><ul><li><strong><code>output_path</code></strong> <em>(str)</em>: The save destination. Default <code>&quot;output_map.png&quot;</code>.</li></ul>',17)])])}const h=o(l,[["render",c]]);export{p as __pageData,h as default};
